insert into public.lesson_blocks (lesson_id, block_type, block_order, content, settings)
values
  ('b1111111-1111-4111-8111-111111111111', 'heading', 1, '{"text":"Ваш старт — не код, а ясная идея"}', '{}'),
  ('b1111111-1111-4111-8111-111111111111', 'paragraph', 2, '{"text":"Чтобы создать первый продукт, не нужно заранее понимать всю разработку. Ваша задача — сформулировать результат, разбить путь на маленькие шаги и использовать ИИ как наставника: показывать контекст, скриншоты, ошибки и просить объяснить следующий шаг простыми словами."}', '{}'),
  ('b1111111-1111-4111-8111-111111111111', 'callout', 3, '{"title":"Главное правило курса","text":"Не пытайтесь знать всё заранее. Заканчивайте один понятный шаг, проверяйте результат и только потом переходите дальше.","tone":"accent"}', '{}'),
  ('b1111111-1111-4111-8111-111111111111', 'checklist', 4, '{"title":"Подготовка","items":["Аккаунт ChatGPT","Установленный Codex","Аккаунт GitHub","Аккаунты Supabase и Netlify","Одна идея первого продукта"]}', '{}'),
  ('b1111111-1111-4111-8111-111111111111', 'prompt', 5, '{"title":"Прояснить идею","description":"Превращает сырую мысль в проверяемую концепцию.","text":"Выступи как продуктовый наставник. Задавай мне по одному простому вопросу, чтобы уточнить идею цифрового продукта: для кого он, какую проблему решает, какой главный результат даёт и какую минимальную версию можно создать за 7 дней. В конце собери ответы в краткое описание продукта."}', '{}'),
  ('b1111111-1111-4111-8111-111111111111', 'prompt', 6, '{"title":"Разбить непонятный шаг","description":"Используйте, когда не знаете, что делать дальше.","text":"Я новичок и сейчас застрял на следующем шаге: [опишите шаг]. Объясни его без жаргона, разбей на действия по 10–15 минут, укажи ожидаемый результат каждого действия и попроси меня прислать результат перед продолжением."}', '{}'),

  ('b2222222-2222-4222-8222-222222222222', 'heading', 1, '{"text":"Лендинг — это один ясный маршрут"}', '{}'),
  ('b2222222-2222-4222-8222-222222222222', 'paragraph', 2, '{"text":"Сильный сайт ведёт человека от первого обещания к одному действию. Начните с оффера, покажите проблему, преимущества и доказательство, затем завершите понятным призывом."}', '{}'),
  ('b2222222-2222-4222-8222-222222222222', 'checklist', 3, '{"title":"Перед публикацией","items":["Один главный CTA","Понятный первый экран","Нет горизонтального скролла","Текст читается на телефоне","Все ссылки работают","Сайт опубликован на Netlify"]}', '{}'),
  ('b2222222-2222-4222-8222-222222222222', 'prompt', 4, '{"title":"Структура лендинга","description":"Создаёт последовательность секций.","text":"Ты — продуктовый дизайнер. Для продукта [описание] и аудитории [аудитория] предложи структуру одностраничного лендинга. Для каждой секции укажи цель, заголовок, ключевой тезис и действие. Сохрани один главный CTA и не добавляй секции без функции."}', '{}'),
  ('b2222222-2222-4222-8222-222222222222', 'prompt', 5, '{"title":"Мастер-промпт для Codex","description":"Основа для реализации сайта.","text":"Создай production-ready адаптивный лендинг по приложенной структуре и референсам. Используй Next.js, TypeScript и Tailwind CSS. Сначала изучи репозиторий, затем реализуй все секции и состояния. Соблюдай доступность, мобильную адаптацию и визуальную иерархию. Не оставляй кнопки без действий. После работы запусти lint, проверку типов и build."}', '{}'),
  ('b2222222-2222-4222-8222-222222222222', 'prompt', 6, '{"title":"Аудит мобильной версии","description":"Находит проблемы перед публикацией.","text":"Проведи аудит мобильной версии сайта на ширинах 320, 375 и 430 px. Проверь переполнение, размер текста и интерактивных зон, отступы, порядок блоков, формы и fixed-элементы. Исправь найденное и перечисли проверки."}', '{}'),

  ('b3333333-3333-4333-8333-333333333333', 'heading', 1, '{"text":"Бот доставляет, Mini App взаимодействует"}', '{}'),
  ('b3333333-3333-4333-8333-333333333333', 'paragraph', 2, '{"text":"Bot API отвечает за сообщения и кнопку запуска, а Mini App — это веб-интерфейс внутри Telegram. Подлинность пользователя подтверждает только серверная проверка initData, а секреты остаются на сервере."}', '{}'),
  ('b3333333-3333-4333-8333-333333333333', 'checklist', 3, '{"title":"Минимально готовый Mini App","items":["Бот создан через BotFather","HTTPS URL подключён","initData проверяется на сервере","Данные сохраняются в Supabase","Секреты не попали в браузер","Проверено внутри Telegram"]}', '{}'),
  ('b3333333-3333-4333-8333-333333333333', 'prompt', 4, '{"title":"Выбор идеи Mini App","description":"Сужает проект до одной полезной функции.","text":"Предложи 10 идей Telegram Mini App для аудитории [аудитория]. Каждая идея должна решать частую маленькую проблему одной основной функцией, использовать сохранение данных и быть реализуемой новичком за 7 дней. Оцени идеи по полезности и сложности, затем рекомендуй одну."}', '{}'),
  ('b3333333-3333-4333-8333-333333333333', 'prompt', 5, '{"title":"Проектирование сценария","description":"Определяет экраны и переходы.","text":"Спроектируй основной пользовательский сценарий Mini App [идея]. Опиши точку входа из бота, 3–5 экранов, главное действие на каждом экране, состояния загрузки, пустоты и ошибки. Убери всё, что не нужно для первой рабочей версии."}', '{}'),
  ('b3333333-3333-4333-8333-333333333333', 'prompt', 6, '{"title":"Безопасное подключение Telegram","description":"Проверяет авторизацию.","text":"Проверь Telegram Mini App авторизацию: initData должен отправляться на сервер, подпись проверяться по алгоритму Telegram с auth_date, личность не должна браться из initDataUnsafe, а сессия должна храниться в Secure HttpOnly cookie. Найди и исправь отклонения."}', '{}'),

  ('b4444444-4444-4444-8444-444444444444', 'heading', 1, '{"text":"Одна механика, которую хочется повторить"}', '{}'),
  ('b4444444-4444-4444-8444-444444444444', 'paragraph', 2, '{"text":"Не начинайте с большой игры. Создайте короткий цикл: действие — обратная связь — награда — небольшое усложнение. Когда цикл уже интересен, добавьте прогресс, звук и полировку."}', '{}'),
  ('b4444444-4444-4444-8444-444444444444', 'callout', 3, '{"title":"Правило масштаба","text":"Лучшая первая игра — законченная маленькая игра, а не впечатляющий незавершённый мир.","tone":"warning"}', '{}'),
  ('b4444444-4444-4444-8444-444444444444', 'prompt', 4, '{"title":"Генератор идеи игры","description":"Ищет маленькую, законченную механику.","text":"Предложи 12 идей браузерной игры с одной основной механикой, сессией 1–3 минуты и управлением одним пальцем. Для каждой укажи игровой цикл, цель, проигрыш, прогрессию и сложность реализации. Выбери идею, которую новичок закончит за неделю."}', '{}'),
  ('b4444444-4444-4444-8444-444444444444', 'prompt', 5, '{"title":"Короткий GDD","description":"Фиксирует правила до реализации.","text":"Создай одностраничный game design document для идеи [идея]. Включи цель игрока, игровой цикл, управление, правила, прогрессию, баланс первых пяти минут, визуальную обратную связь, звук, сохранение и критерии готовности MVP."}', '{}'),
  ('b4444444-4444-4444-8444-444444444444', 'prompt', 6, '{"title":"Поиск багов","description":"Проверяет игровой цикл и мобильное управление.","text":"Протестируй игру как QA-инженер: быстрые повторные нажатия, пауза и возврат, перезапуск, потеря фокуса, разные размеры экрана, касание края, сброс и восстановление прогресса. Исправь воспроизводимые ошибки и составь короткий отчёт."}', '{}'),

  ('b5555555-5555-4555-8555-555555555555', 'heading', 1, '{"text":"Монетизируйте результат, а не обещание"}', '{}'),
  ('b5555555-5555-4555-8555-555555555555', 'paragraph', 2, '{"text":"Ваши сайт, Mini App и игра — уже кейсы. Выберите одну понятную услугу или продукт, конкретного клиента и измеримый результат. Первые продажи начинаются с разговоров и демонстрации, а не с идеальной упаковки."}', '{}'),
  ('b5555555-5555-4555-8555-555555555555', 'callout', 3, '{"title":"Важно","text":"Курс не гарантирует доход. Результат зависит от качества продукта, рынка, последовательности действий и вашей работы с клиентами.","tone":"warning"}', '{}'),
  ('b5555555-5555-4555-8555-555555555555', 'checklist', 4, '{"title":"План на 30 дней","items":["Одна услуга или продукт","Один сегмент клиентов","Стартовая цена","20 потенциальных клиентов","3 демонстрации","Еженедельный разбор результатов"]}', '{}'),
  ('b5555555-5555-4555-8555-555555555555', 'prompt', 5, '{"title":"Упаковать предложение","description":"Превращает навык в ясный оффер.","text":"Помоги упаковать предложение на основе моего проекта [проект]. Определи клиента, проблему, измеримый результат, состав работы, срок, ограничения и стартовую цену. Напиши короткое сообщение для первого контакта без громких обещаний и давления."}', '{}'),
  ('b5555555-5555-4555-8555-555555555555', 'prompt', 6, '{"title":"План первых клиентов","description":"Создаёт реалистичные действия.","text":"Составь план поиска первых трёх клиентов за 30 дней для услуги [услуга]. У меня есть кейсы [кейсы] и доступно [часы] часов в неделю. Дай ежедневные действия, каналы, метрики, шаблон сообщения и правило еженедельной корректировки."}', '{}')
on conflict (lesson_id, block_order) do update set block_type = excluded.block_type, content = excluded.content, settings = excluded.settings;

